def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # right should be the index of the last element

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1  # If arr[mid] is too small, search in the right half
        else:
            right = mid - 1 # If arr[mid] is too large, search in the left half

    return -1

